1	/* ABOUTME: Brutalist mono UI — Direction C. Single font (JetBrains Mono),  */
2	/* ABOUTME: hairline borders, zero radius, glyph-based status, single accent. */
3	
4	/* ============================================================
5	   TOKENS
6	   ============================================================ */
7	
8	:root {
9	  /* Light — warm paper */
10	  --bg-primary:    #f6f5f0;
11	  --bg-secondary:  #f6f5f0;
12	  --bg-hover:      #ecebe5;
13	  --bg-surface:    #ecebe5;
14	
15	  --text-primary:   #111111;
16	  --text-secondary: #4a4a4a;
17	  --text-muted:     #888888;
18	
19	  --border:       #d8d6cf;
20	  --border-light: #e2e0d9;
21	
22	  /* Single accent */
23	  --accent:     #ff5b1f;
24	  --accent-dim: rgba(255, 91, 31, 0.10);
25	
26	  /* Status — text colour only; visual state comes from glyphs */
27	  --status-in-progress:        var(--accent);
28	  --status-likely-in-progress: var(--text-primary);
29	  --status-waiting:            var(--accent);
30	  --status-done:               var(--text-primary);
31	  --status-likely-done:        var(--text-muted);
32	
33	  --badge-claude: var(--text-primary);
34	  --badge-codex:  var(--text-secondary);
35	
36	  --bg-code:           #ecebe5;
37	  --border-code:       #d8d6cf;
38	  --bg-code-inline:    rgba(0, 0, 0, 0.05);
39	  --bg-table-header:   rgba(0, 0, 0, 0.03);
40	  --border-table:      #c9c7c0;
41	
42	  --radius: 0;
43	  --transition: 80ms linear;
44	
45	  --font-display: "JetBrains Mono", ui-monospace, "SF Mono", monospace;
46	  --font-body:    "JetBrains Mono", ui-monospace, "SF Mono", monospace;
47	  --font-mono:    "JetBrains Mono", ui-monospace, "SF Mono", monospace;
48	
49	  --font-size-xs:   10px;
50	  --font-size-sm:   11px;
51	  --font-size-base: 12px;
52	  --font-size-md:   13px;
53	  --font-size-lg:   15px;
54	  --font-size-xl:   18px;
55	  --font-size-2xl:  22px;
56	}
57	
58	/* ============================================================
59	   RESET
60	   ============================================================ */
61	
62	* { margin: 0; padding: 0; box-sizing: border-box; }
63	
64	body {
65	  font-family: var(--font-body);
66	  font-weight: 400;
67	  font-size: var(--font-size-base);
68	  background: var(--bg-primary);
69	  color: var(--text-primary);
70	  line-height: 1.5;
71	  min-height: 100vh;
72	  -webkit-font-smoothing: antialiased;
73	}
74	
75	::-webkit-scrollbar { width: 6px; height: 6px; }
76	::-webkit-scrollbar-thumb { background: var(--border); }
77	::-webkit-scrollbar-track { background: transparent; }
78	
79	/* ============================================================
80	   HEADER
81	   ============================================================ */
82	
83	.header {
84	  display: flex;
85	  align-items: center;
86	  justify-content: space-between;
87	  padding: 10px 18px;
88	  border-bottom: 1px solid var(--border);
89	  background: var(--bg-primary);
90	  position: sticky;
91	  top: 0;
92	  z-index: 50;
93	}
94	
95	.header-left { display: flex; align-items: center; gap: 10px; }
96	
97	.header-logo,
98	.header-logo-glyph {
99	  flex-shrink: 0;
100	  color: var(--accent);
101	  font-family: var(--font-mono);
102	  font-size: 16px;
103	  font-weight: 700;
104	  line-height: 1;
105	}
106	
107	.header-title {
108	  font-family: var(--font-mono);
109	  font-size: 14px;
110	  font-weight: 700;
111	  letter-spacing: 0.04em;
112	  color: var(--text-primary);
113	  text-transform: lowercase;
114	}
115	
116	.header-right { display: flex; align-items: center; gap: 14px; }
117	
118	.last-scan {
119	  font-family: var(--font-mono);
120	  font-size: var(--font-size-xs);
121	  letter-spacing: 0.02em;
122	  color: var(--text-muted);
123	}
124	
125	/* Scan-days input */
126	.scan-days-label {
127	  display: flex;
128	  align-items: center;
129	  border: 1px solid var(--border);
130	  background: transparent;
131	  padding: 0 8px 0 0;
132	}
133	.scan-days-input {
134	  font-family: var(--font-mono);
135	  font-size: var(--font-size-xs);
136	  font-weight: 500;
137	  width: 36px;
138	  padding: 4px 2px 4px 8px;
139	  border: none;
140	  background: transparent;
141	  color: var(--text-primary);
142	  text-align: right;
143	  -moz-appearance: textfield;
144	}
145	.scan-days-input::-webkit-inner-spin-button,
146	.scan-days-input::-webkit-outer-spin-button { -webkit-appearance: none; margin: 0; }
147	.scan-days-input:focus { outline: none; }
148	.scan-days-suffix {
149	  font-family: var(--font-mono);
150	  font-size: var(--font-size-xs);
151	  font-weight: 500;
152	  letter-spacing: 0.04em;
153	  color: var(--text-muted);
154	  padding-left: 2px;
155	}
156	
157	/* Refresh / theme buttons */
158	.btn-refresh {
159	  padding: 5px 14px;
160	  border: 1px solid var(--accent);
161	  background: var(--accent);
162	  color: #fff;
163	  font-family: var(--font-mono);
164	  font-weight: 600;
165	  font-size: var(--font-size-xs);
166	  letter-spacing: 0.06em;
167	  cursor: pointer;
168	  transition: opacity var(--transition);
169	}
170	.btn-refresh:hover { opacity: 0.85; }
171	.btn-refresh:active { opacity: 0.7; }
172	.btn-refresh.spinning { opacity: 0.4; pointer-events: none; }
173	
174	.theme-toggle {
175	  font-family: var(--font-mono);
176	  font-size: var(--font-size-xs);
177	  color: var(--text-muted);
178	  background: transparent;
179	  border: 1px solid var(--border);
180	  padding: 4px 10px;
181	  cursor: pointer;
182	  transition: color var(--transition), border-color var(--transition);
183	  letter-spacing: 0.04em;
184	}
185	.theme-toggle:hover { color: var(--text-primary); border-color: var(--text-muted); }
186	
187	/* ============================================================
188	   APP LAYOUT
189	   ============================================================ */
190	
191	.app-layout {
192	  display: flex;
193	  height: calc(100vh - 41px);
194	  overflow: hidden;
195	}
196	
197	/* ============================================================
198	   SIDEBAR
199	   ============================================================ */
200	
201	.sidebar {
202	  width: 320px;          /* shrunk from 340px */
203	  min-width: 240px;
204	  max-width: 50vw;
205	  flex-shrink: 0;
206	  display: flex;
207	  flex-direction: column;
208	  background: var(--bg-primary);
209	  border-right: 1px solid var(--border);
210	  overflow: hidden;
211	  transition: width 150ms linear, min-width 150ms linear;
212	}
213	.sidebar.collapsed {
214	  width: 0; min-width: 0; border-right: none; overflow: hidden;
215	}
216	
217	.sidebar-header {
218	  display: flex;
219	  align-items: stretch;
220	  padding: 0;
221	  border-bottom: 1px solid var(--border);
222	  flex-shrink: 0;
223	  gap: 0;
224	}
225	
226	.sidebar-toggle {
227	  width: 32px;
228	  border: none;
229	  border-left: 1px solid var(--border);
230	  background: transparent;
231	  color: var(--text-muted);
232	  cursor: pointer;
233	  font-size: 14px;
234	  flex-shrink: 0;
235	  transition: color var(--transition);
236	}
237	.sidebar-toggle:hover { color: var(--accent); }
238	
239	.sidebar-search {
240	  font-family: var(--font-mono);
241	  font-size: var(--font-size-sm);
242	  color: var(--text-muted);
243	  padding: 6px 14px;
244	  cursor: pointer;
245	  border-bottom: 1px solid var(--border);
246	  flex-shrink: 0;
247	  display: flex;
248	  align-items: center;
249	  gap: 8px;
250	}
251	.sidebar-search:hover { background: var(--bg-hover); color: var(--text-primary); }
252	.sidebar-search kbd {
253	  font-family: var(--font-mono);
254	  font-size: 10px;
255	  background: transparent;
256	  border: 1px solid var(--border);
257	  padding: 0 5px;
258	  color: var(--text-secondary);
259	}
260	
261	.sidebar-content {
262	  flex: 1;
263	  overflow-y: auto;
264	  padding: 0;
265	}
266	
267	.sidebar-resize-handle {
268	  width: 1px;
269	  cursor: ew-resize;
270	  background: var(--border);
271	  flex-shrink: 0;
272	  transition: background var(--transition);
273	}
274	.sidebar-resize-handle:hover { background: var(--accent); width: 2px; }
275	
276	/* Time segments — full-width segmented control */
277	.time-segments {
278	  display: flex;
279	  flex: 1;
280	  border: none;
281	}
282	
283	.time-seg {
284	  font-family: var(--font-mono);
285	  font-size: var(--font-size-xs);
286	  font-weight: 500;
287	  letter-spacing: 0.04em;
288	  padding: 8px 0;
289	  border: none;
290	  border-right: 1px solid var(--border);
291	  background: transparent;
292	  color: var(--text-secondary);
293	  cursor: pointer;
294	  transition: background var(--transition), color var(--transition);
295	  flex: 1;
296	  text-align: center;
297	}
298	.time-seg:hover { background: var(--bg-hover); color: var(--text-primary); }
299	.time-seg.active {
300	  background: var(--text-primary);
301	  color: var(--bg-primary);
302	  font-weight: 600;
303	}
304	
305	/* ============================================================
306	   OVERLAYS — search & help
307	   ============================================================ */
308	
309	.search-overlay,
310	.help-overlay {
311	  position: fixed;
312	  inset: 0;
313	  background: rgba(0, 0, 0, 0.35);
314	  z-index: 200;
315	  display: flex;
316	  justify-content: center;
317	}
318	.search-overlay { padding-top: 12vh; }
319	.help-overlay { padding-top: 18vh; }
320	.search-overlay.hidden, .help-overlay.hidden { display: none; }
321	
322	.search-box {
323	  width: 620px;
324	  max-width: 90vw;
325	  background: var(--bg-primary);
326	  border: 1px solid var(--text-primary);
327	  max-height: 60vh;
328	  display: flex;
329	  flex-direction: column;
330	  align-self: flex-start;
331	  overflow: hidden;
332	}
333	
334	.search-input-row {
335	  display: flex;
336	  align-items: center;
337	  padding: 10px 14px;
338	  border-bottom: 1px solid var(--border);
339	  gap: 10px;
340	}
341	.search-icon {
342	  font-family: var(--font-mono);
343	  font-size: 16px;
344	  font-weight: 600;
345	  color: var(--accent);
346	}
347	.search-input {
348	  flex: 1;
349	  font-family: var(--font-mono);
350	  font-size: 14px;
351	  font-weight: 500;
352	  border: none;
353	  background: transparent;
354	  color: var(--text-primary);
355	  outline: none;
356	}
357	.search-input::placeholder { color: var(--text-muted); }
358	.search-hint {
359	  font-family: var(--font-mono);
360	  font-size: 10px;
361	  color: var(--text-muted);
362	  background: transparent;
363	  padding: 1px 5px;
364	  border: 1px solid var(--border);
365	}
366	
367	.search-results { overflow-y: auto; max-height: calc(60vh - 50px); }
368	
369	.search-result-row {
370	  display: grid;
371	  grid-template-columns: 10px 1fr auto auto;
372	  align-items: center;
373	  gap: 12px;
374	  padding: 6px 14px;
375	  cursor: pointer;
376	  border-bottom: 1px solid var(--border-light);
377	}
378	.search-result-row:hover,
379	.search-result-row.selected { background: var(--bg-hover); }
380	.search-result-row.selected {
381	  border-left: 2px solid var(--accent);
382	  padding-left: 12px;
383	}
384	.search-result-repo {
385	  font-family: var(--font-mono);
386	  font-size: var(--font-size-xs);
387	  color: var(--text-muted);
388	}
389	.search-result-summary {
390	  font-family: var(--font-mono);
391	  font-size: var(--font-size-md);
392	  color: var(--text-secondary);
393	  white-space: nowrap;
394	  overflow: hidden;
395	  text-overflow: ellipsis;
396	}
397	.search-result-summary mark {
398	  background: transparent;
399	  color: var(--accent);
400	  font-weight: 700;
401	}
402	.search-no-results {
403	  padding: 24px 14px;
404	  text-align: center;
405	  color: var(--text-muted);
406	  font-size: var(--font-size-md);
407	}
408	
409	/* Help */
410	.help-box {
411	  width: 380px;
412	  max-width: 90vw;
413	  background: var(--bg-primary);
414	  border: 1px solid var(--text-primary);
415	  align-self: flex-start;
416	  padding: 18px 22px;
417	}
418	.help-title {
419	  font-family: var(--font-mono);
420	  font-size: 13px;
421	  font-weight: 700;
422	  color: var(--text-primary);
423	  letter-spacing: 0.04em;
424	  margin-bottom: 14px;
425	}
426	.help-shortcuts { display: flex; flex-direction: column; gap: 6px; }
427	.help-row {
428	  display: flex; align-items: center; gap: 14px;
429	  font-family: var(--font-mono);
430	  font-size: var(--font-size-md);
431	  color: var(--text-secondary);
432	}
433	.help-row kbd {
434	  font-family: var(--font-mono);
435	  font-size: 11px;
436	  font-weight: 500;
437	  min-width: 56px;
438	  text-align: center;
439	  padding: 1px 6px;
440	  background: transparent;
441	  border: 1px solid var(--border);
442	  color: var(--text-primary);
443	}
444	.help-dismiss {
445	  margin-top: 14px;
446	  padding-top: 10px;
447	  border-top: 1px solid var(--border);
448	  font-family: var(--font-mono);
449	  font-size: var(--font-size-sm);
450	  color: var(--text-muted);
451	  text-align: center;
452	}
453	.help-dismiss kbd {
454	  font-family: var(--font-mono);
455	  font-size: 10px;
456	  padding: 0 4px;
457	  border: 1px solid var(--border);
458	}
459	
460	/* ============================================================
461	   GROUP FOCUS (j/k nav)
462	   ============================================================ */
463	
464	.repo-group.group-focused > .repo-header {
465	  background: var(--accent-dim);
466	  border-left: 2px solid var(--accent);
467	}
468	
469	/* ============================================================
470	   CONTENT
471	   ============================================================ */
472	
473	.hidden { display: none !important; }
474	
475	.loading {
476	  text-align: center;
477	  padding: 32px;
478	  color: var(--text-muted);
479	  font-size: var(--font-size-md);
480	}
481	
482	.empty-state {
483	  text-align: center;
484	  padding: 32px 16px;
485	  color: var(--text-secondary);
486	  font-size: var(--font-size-md);
487	}
488	.empty-state-title {
489	  font-family: var(--font-mono);
490	  font-size: 13px;
491	  font-weight: 700;
492	  color: var(--text-primary);
493	  margin-bottom: 12px;
494	  letter-spacing: 0.04em;
495	}
496	.empty-state-body { line-height: 1.6; }
497	.empty-state-body p { margin-bottom: 6px; }
498	.empty-state code {
499	  font-family: var(--font-mono);
500	  background: var(--bg-surface);
501	  padding: 1px 5px;
502	  font-size: 12px;
503	  border: 1px solid var(--border);
504	}
505	
506	/* ============================================================
507	   REPO GROUP
508	   ============================================================ */
509	
510	.repo-group {
511	  margin: 0;
512	  background: transparent;
513	  border: none;
514	  border-bottom: 1px solid var(--border);
515	  overflow: hidden;
516	}
517	
518	.repo-header {
519	  display: flex;
520	  align-items: center;
521	  justify-content: space-between;
522	  padding: 10px 14px;
523	  cursor: pointer;
524	  transition: background var(--transition);
525	  user-select: none;
526	}
527	.repo-header:hover { background: var(--bg-hover); }
528	
529	.repo-header-left { display: flex; align-items: center; gap: 8px; }
530	
531	.repo-chevron {
532	  font-size: 10px;
533	  color: var(--text-muted);
534	  transition: transform 100ms linear;
535	  width: 12px;
536	  text-align: center;
537	}
538	.repo-chevron.expanded { transform: rotate(90deg); }
539	
540	.octocat-icon { opacity: 0.4; margin-right: 2px; vertical-align: -1px; flex-shrink: 0; }
541	
542	.repo-header-info { display: flex; flex-direction: column; gap: 1px; }
543	
544	.repo-name-display {
545	  font-family: var(--font-mono);
546	  font-weight: 700;
547	  font-size: var(--font-size-md);
548	  letter-spacing: 0;
549	  line-height: 1.2;
550	  color: var(--text-primary);
551	}
552	
553	.repo-meta-line {
554	  font-family: var(--font-mono);
555	  font-size: var(--font-size-sm);
556	  color: var(--text-muted);
557	  line-height: 1.3;
558	}
559	
560	.meta-sep {
561	  margin: 0 5px;
562	  color: var(--border);
563	  font-weight: 400;
564	}
565	
566	.repo-meta-line .meta-branch { color: var(--text-secondary); }
567	.repo-meta-line .dirty       { color: var(--accent); font-weight: 600; }
568	.repo-meta-line .unpushed    { color: var(--accent); font-weight: 600; }
569	.repo-meta-line .clean       { color: var(--text-secondary); }
570	.repo-meta-line .meta-count  { color: var(--text-muted); }
571	
572	.repo-header-right {
573	  display: flex;
574	  align-items: center;
575	  gap: 8px;
576	  font-family: var(--font-mono);
577	  font-size: var(--font-size-sm);
578	  color: var(--text-muted);
579	}
580	
581	.btn-new-session {
582	  width: 22px;
583	  height: 22px;
584	  border: 1px solid var(--border);
585	  background: transparent;
586	  color: var(--text-muted);
587	  font-family: var(--font-mono);
588	  font-size: 14px;
589	  font-weight: 500;
590	  line-height: 1;
591	  cursor: pointer;
592	  display: flex;
593	  align-items: center;
594	  justify-content: center;
595	  transition: color var(--transition), border-color var(--transition), background var(--transition);
596	}
597	.btn-new-session:hover {
598	  background: var(--accent);
599	  border-color: var(--accent);
600	  color: #fff;
601	}
602	
603	/* ============================================================
604	   REPO TIMELINE
605	   ============================================================ */
606	
607	.repo-timeline {
608	  padding: 6px 14px 8px;
609	  border-top: 1px dashed var(--border);
610	}
611	.timeline-prose {
612	  margin: 0;
613	  font-family: var(--font-mono);
614	  font-size: var(--font-size-sm);
615	  line-height: 1.5;
616	  color: var(--text-secondary);
617	}
618	.timeline-link {
619	  color: var(--accent);
620	  text-decoration: none;
621	  cursor: pointer;
622	}
623	.timeline-link:hover { text-decoration: underline; }
624	
625	/* ============================================================
626	   SESSION LIST + ROW
627	   ============================================================ */
628	
629	.session-list { margin: 0; border: none; overflow: hidden; transition: max-height 200ms ease; }
630	.session-list.collapsed { max-height: 0 !important; }
631	
632	.session-row {
633	  display: grid;
634	  grid-template-columns: 12px 1fr auto auto;
635	  align-items: center;
636	  gap: 8px;
637	  padding: 5px 14px;
638	  cursor: pointer;
639	  transition: background var(--transition);
640	  line-height: 1.4;
641	  border-left: 2px solid transparent;
642	  border-bottom: 1px solid var(--border-light);
643	}
644	.session-row:last-child,
645	.session-row:has(+ .show-more-btn) { border-bottom: none; }
646	.session-row:hover { background: var(--bg-hover); }
647	
648	/* ============================================================
649	   STATUS DOT — replaced with glyphs via ::before
650	   ============================================================ */
651	
652	.status-dot {
653	  width: 12px;
654	  height: 16px;
655	  background: transparent !important;
656	  border-radius: 0 !important;
657	  flex-shrink: 0;
658	  position: relative;
659	  animation: none !important;
660	  box-shadow: none !important;
661	}
662	.status-dot::before {
663	  position: absolute;
664	  inset: 0;
665	  display: flex;
666	  align-items: center;
667	  justify-content: center;
668	  font-family: var(--font-mono);
669	  font-size: 12px;
670	  line-height: 1;
671	}
672	.status-dot.in-progress::before        { content: "◐"; color: var(--accent); }
673	.status-dot.likely-in-progress::before { content: "◑"; color: var(--text-primary); }
674	.status-dot.waiting-for-input::before  { content: "◌"; color: var(--accent); }
675	.status-dot.done::before               { content: "●"; color: var(--text-primary); }
676	.status-dot.likely-done::before        { content: "◯"; color: var(--text-muted); }
677	
678	/* ============================================================
679	   SESSION SUMMARY
680	   ============================================================ */
681	
682	.session-summary {
683	  font-family: var(--font-mono);
