1294	.chat-plan-entry.failed    { color: var(--accent); }
1295	.chat-plan-icon { margin-right: 6px; }
1296	
1297	.chat-system-msg {
1298	  text-align: center;
1299	  font-family: var(--font-mono);
1300	  font-size: var(--font-size-sm);
1301	  color: var(--text-muted);
1302	  padding: 6px;
1303	}
1304	
1305	.chat-local-command {
1306	  display: flex; align-items: center; gap: 6px;
1307	  padding: 2px 0;
1308	  margin: 2px 0;
1309	  font-family: var(--font-mono);
1310	  font-size: var(--font-size-sm);
1311	  color: var(--text-muted);
