1313	.chat-local-cmd-icon::before { content: "$"; color: var(--accent); }
1314	.chat-local-cmd-name { color: var(--text-secondary); }
1315	.chat-local-cmd-output { opacity: 0.6; font-style: normal; }
1316	
1317	.chat-terminated {
1318	  color: var(--accent);
1319	  border: 1px solid var(--accent);
1320	  padding: 8px 12px;
1321	  margin: 8px 0;
1322	  font-family: var(--font-mono);
1323	}
1324	
1325	.chat-info-banner {
1326	  background: transparent;
1327	  border: 1px dashed var(--accent);
1328	  padding: 8px 12px;
1329	  font-family: var(--font-mono);
1330	  font-size: var(--font-size-sm);
1331	  color: var(--text-secondary);
1332	  margin: 8px 0;
1333	}
1334	
1335	.chat-auth-banner {
1336	  background: var(--accent-dim);
1337	  border: 1px solid var(--accent);
1338	  padding: 12px;
1339	  margin: 8px 0;
1340	  text-align: center;
1341	}
1342	.chat-auth-text {
1343	  font-family: var(--font-mono);
1344	  font-size: var(--font-size-sm);
1345	  color: var(--accent);
1346	  margin-bottom: 8px;
1347	}
1348	.chat-auth-retry {
1349	  font-family: var(--font-mono);
1350	  font-size: var(--font-size-sm);
1351	  padding: 4px 16px;
1352	  background: var(--accent);
1353	  color: #fff;
1354	  border: none;
1355	  cursor: pointer;
1356	}
1357	.chat-auth-retry:hover { opacity: 0.85; }
1358	
1359	/* Image preview */
1360	.chat-image-preview {
1361	  display: none;
1362	  flex-shrink: 0;
1363	  gap: 8px;
1364	  padding: 6px 14px 0;
1365	  background: var(--bg-primary);
1366	  border-top: 1px solid var(--border);
1367	  overflow-x: auto;
1368	}
1369	.chat-image-preview.active { display: flex; }
1370	.image-preview-thumb { position: relative; flex-shrink: 0; }
1371	.image-preview-thumb img {
1372	  height: 56px;
1373	  max-width: 120px;
1374	  object-fit: cover;
1375	  border: 1px solid var(--border);
1376	}
1377	.image-preview-remove {
1378	  position: absolute;
1379	  top: 0; right: 0;
1380	  width: 16px; height: 16px;
1381	  border: 1px solid var(--text-primary);
1382	  background: var(--bg-primary);
1383	  color: var(--text-primary);
1384	  font-size: 11px;
1385	  line-height: 1;
1386	  cursor: pointer;
1387	  display: flex; align-items: center; justify-content: center;
1388	}
1389	.image-preview-remove:hover { background: var(--accent); color: #fff; border-color: var(--accent); }
1390	
1391	.chat-bubble-images {
1392	  display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 6px;
1393	}
1394	.chat-bubble-img {
1395	  max-width: 300px; max-height: 200px;
1396	  border: 1px solid var(--border);
1397	  object-fit: contain;
1398	}
1399	
1400	/* Input bar */
1401	.chat-input-bar {
1402	  display: flex;
1403	  align-items: center;
1404	  gap: 8px;
1405	  padding: 8px 14px;
1406	  background: var(--bg-primary);
1407	  border-top: 1px solid var(--border);
1408	  flex-shrink: 0;
1409	}
1410	.chat-input-prompt {
1411	  font-family: var(--font-mono);
1412	  font-size: 14px;
1413	  font-weight: 600;
1414	  color: var(--accent);
1415	  flex-shrink: 0;
1416	}
1417	
1418	.chat-input {
1419	  flex: 1;
1420	  background: transparent;
1421	  color: var(--text-primary);
1422	  border: none;
1423	  border-bottom: 1px solid var(--border);
1424	  padding: 6px 0;
1425	  font-family: var(--font-mono);
1426	  font-size: var(--font-size-md);
1427	  resize: none;
1428	  outline: none;
1429	  max-height: 120px;
1430	  line-height: 1.4;
1431	}
1432	.chat-input:focus { border-bottom-color: var(--accent); }
1433	.chat-input:disabled { opacity: 0.5; }
1434	
1435	.chat-send-btn {
1436	  background: transparent;
1437	  color: var(--accent);
1438	  border: 1px solid var(--accent);
1439	  padding: 4px 10px;
1440	  font-family: var(--font-mono);
1441	  font-size: var(--font-size-sm);
1442	  font-weight: 600;
1443	  letter-spacing: 0.04em;
1444	  cursor: pointer;
1445	  flex-shrink: 0;
1446	  border-radius: 0;
1447	  width: auto;
1448	  height: auto;
1449	}
1450	.chat-send-btn:hover { background: var(--accent); color: #fff; }
1451	.chat-send-btn:disabled { opacity: 0.3; cursor: default; }
1452	
1453	.chat-stop-btn {
1454	  background: transparent;
1455	  color: var(--accent);
1456	  border: 1px solid var(--accent);
1457	  padding: 4px 10px;
1458	  font-family: var(--font-mono);
1459	  font-size: var(--font-size-sm);
1460	  font-weight: 600;
1461	  cursor: pointer;
1462	  flex-shrink: 0;
1463	  border-radius: 0;
1464	  width: auto;
1465	  height: auto;
1466	}
1467	.chat-stop-btn:hover { background: var(--accent); color: #fff; }
1468	.chat-stop-btn.hidden { display: none; }
1469	
1470	/* ============================================================
1471	   RESPONSIVE
1472	   ============================================================ */
1473	
1474	@media (max-width: 800px) {
1475	  .header { padding-left: 14px; padding-right: 14px; }
1476	  .header-title { font-size: 13px; }
1477	  .app-layout { flex-direction: column; }
1478	  .sidebar {
1479	    width: 100% !important;
1480	    max-width: 100vw;
