1486	  .sidebar-resize-handle { display: none; }
1487	  .session-row { grid-template-columns: 12px 1fr auto; gap: 8px; }
1488	  .status-label, .time-ago { display: none; }
1489	  .chat-bubble.assistant { max-width: 100%; }
1490	  .chat-turn-sidebar { display: none; }
1491	}
1492	
1493	/* ============================================================
1494	   DARK MODE
1495	   ============================================================ */
1496	
1497	html.dark {
1498	  --bg-primary:    #0a0a0a;
1499	  --bg-secondary:  #0a0a0a;
1500	  --bg-hover:      #161616;
1501	  --bg-surface:    #121212;
1502	
