/* ABOUTME: Brutalist mono UI — Direction C. Single font (JetBrains Mono),  */
/* ABOUTME: hairline borders, zero radius, glyph-based status, single accent. */

/* ============================================================
   TOKENS
   ============================================================ */

:root {
  /* Light — warm paper */
  --bg-primary:    #f6f5f0;
  --bg-secondary:  #f6f5f0;
  --bg-hover:      #ecebe5;
  --bg-surface:    #ecebe5;

  --text-primary:   #111111;
  --text-secondary: #4a4a4a;
  --text-muted:     #888888;

  --border:       #d8d6cf;
  --border-light: #e2e0d9;

  /* Single accent */
  --accent:     #ff5b1f;
  --accent-dim: rgba(255, 91, 31, 0.10);

  /* Status — text colour only; visual state comes from glyphs */
  --status-in-progress:        var(--accent);
  --status-likely-in-progress: var(--text-primary);
  --status-waiting:            var(--accent);
  --status-done:               var(--text-primary);
  --status-likely-done:        var(--text-muted);

  --badge-claude: var(--text-primary);
  --badge-codex:  var(--text-secondary);

  --bg-code:           #ecebe5;
  --border-code:       #d8d6cf;
  --bg-code-inline:    rgba(0, 0, 0, 0.05);
  --bg-table-header:   rgba(0, 0, 0, 0.03);
  --border-table:      #c9c7c0;

  --radius: 0;
  --transition: 80ms linear;

  --font-display: "JetBrains Mono", ui-monospace, "SF Mono", monospace;
  --font-body:    "JetBrains Mono", ui-monospace, "SF Mono", monospace;
  --font-mono:    "JetBrains Mono", ui-monospace, "SF Mono", monospace;

  --font-size-xs:   10px;
  --font-size-sm:   11px;
  --font-size-base: 12px;
  --font-size-md:   13px;
  --font-size-lg:   15px;
  --font-size-xl:   18px;
  --font-size-2xl:  22px;
}

/* ============================================================
   RESET
   ============================================================ */

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  font-family: var(--font-body);
  font-weight: 400;
  font-size: var(--font-size-base);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.5;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-thumb { background: var(--border); }
::-webkit-scrollbar-track { background: transparent; }

/* ============================================================
   HEADER
   ============================================================ */

.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 18px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-primary);
  position: sticky;
  top: 0;
  z-index: 50;
}

.header-left { display: flex; align-items: center; gap: 10px; }

.header-logo,
.header-logo-glyph {
  flex-shrink: 0;
  color: var(--accent);
  font-family: var(--font-mono);
  font-size: 16px;
  font-weight: 700;
  line-height: 1;
}

.header-title {
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--text-primary);
  text-transform: lowercase;
}

.header-right { display: flex; align-items: center; gap: 14px; }

.last-scan {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  letter-spacing: 0.02em;
  color: var(--text-muted);
}

/* Scan-days input */
.scan-days-label {
  display: flex;
  align-items: center;
  border: 1px solid var(--border);
  background: transparent;
  padding: 0 8px 0 0;
}
.scan-days-input {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  width: 36px;
  padding: 4px 2px 4px 8px;
  border: none;
  background: transparent;
  color: var(--text-primary);
  text-align: right;
  -moz-appearance: textfield;
}
.scan-days-input::-webkit-inner-spin-button,
.scan-days-input::-webkit-outer-spin-button { -webkit-appearance: none; margin: 0; }
.scan-days-input:focus { outline: none; }
.scan-days-suffix {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  letter-spacing: 0.04em;
  color: var(--text-muted);
  padding-left: 2px;
}

/* Refresh / theme buttons */
.btn-refresh {
  padding: 5px 14px;
  border: 1px solid var(--accent);
  background: var(--accent);
  color: #fff;
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: var(--font-size-xs);
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: opacity var(--transition);
}
.btn-refresh:hover { opacity: 0.85; }
.btn-refresh:active { opacity: 0.7; }
.btn-refresh.spinning { opacity: 0.4; pointer-events: none; }

.theme-toggle {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  color: var(--text-muted);
  background: transparent;
  border: 1px solid var(--border);
  padding: 4px 10px;
  cursor: pointer;
  transition: color var(--transition), border-color var(--transition);
  letter-spacing: 0.04em;
}
.theme-toggle:hover { color: var(--text-primary); border-color: var(--text-muted); }

/* ============================================================
   APP LAYOUT
   ============================================================ */

.app-layout {
  display: flex;
  height: calc(100vh - 41px);
  overflow: hidden;
}

/* ============================================================
   SIDEBAR
   ============================================================ */

.sidebar {
  width: 320px;          /* shrunk from 340px */
  min-width: 240px;
  max-width: 50vw;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  background: var(--bg-primary);
  border-right: 1px solid var(--border);
  overflow: hidden;
  transition: width 150ms linear, min-width 150ms linear;
}
.sidebar.collapsed {
  width: 0; min-width: 0; border-right: none; overflow: hidden;
}

.sidebar-header {
  display: flex;
  align-items: stretch;
  padding: 0;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  gap: 0;
}

.sidebar-toggle {
  width: 32px;
  border: none;
  border-left: 1px solid var(--border);
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 14px;
  flex-shrink: 0;
  transition: color var(--transition);
}
.sidebar-toggle:hover { color: var(--accent); }

.sidebar-search {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 6px 14px;
  cursor: pointer;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}
.sidebar-search:hover { background: var(--bg-hover); color: var(--text-primary); }
.sidebar-search kbd {
  font-family: var(--font-mono);
  font-size: 10px;
  background: transparent;
  border: 1px solid var(--border);
  padding: 0 5px;
  color: var(--text-secondary);
}

.sidebar-content {
  flex: 1;
  overflow-y: auto;
  padding: 0;
}

.sidebar-resize-handle {
  width: 1px;
  cursor: ew-resize;
  background: var(--border);
  flex-shrink: 0;
  transition: background var(--transition);
}
.sidebar-resize-handle:hover { background: var(--accent); width: 2px; }

/* Time segments — full-width segmented control */
.time-segments {
  display: flex;
  flex: 1;
  border: none;
}

.time-seg {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  letter-spacing: 0.04em;
  padding: 8px 0;
  border: none;
  border-right: 1px solid var(--border);
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  transition: background var(--transition), color var(--transition);
  flex: 1;
  text-align: center;
}
.time-seg:hover { background: var(--bg-hover); color: var(--text-primary); }
.time-seg.active {
  background: var(--text-primary);
  color: var(--bg-primary);
  font-weight: 600;
}

/* ============================================================
   OVERLAYS — search & help
   ============================================================ */

.search-overlay,
.help-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.35);
  z-index: 200;
  display: flex;
  justify-content: center;
}
.search-overlay { padding-top: 12vh; }
.help-overlay { padding-top: 18vh; }
.search-overlay.hidden, .help-overlay.hidden { display: none; }

.search-box {
  width: 620px;
  max-width: 90vw;
  background: var(--bg-primary);
  border: 1px solid var(--text-primary);
  max-height: 60vh;
  display: flex;
  flex-direction: column;
  align-self: flex-start;
  overflow: hidden;
}

.search-input-row {
  display: flex;
  align-items: center;
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
  gap: 10px;
}
.search-icon {
  font-family: var(--font-mono);
  font-size: 16px;
  font-weight: 600;
  color: var(--accent);
}
.search-input {
  flex: 1;
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 500;
  border: none;
  background: transparent;
  color: var(--text-primary);
  outline: none;
}
.search-input::placeholder { color: var(--text-muted); }
.search-hint {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  background: transparent;
  padding: 1px 5px;
  border: 1px solid var(--border);
}

.search-results { overflow-y: auto; max-height: calc(60vh - 50px); }

.search-result-row {
  display: grid;
  grid-template-columns: 10px 1fr auto auto;
  align-items: center;
  gap: 12px;
  padding: 6px 14px;
  cursor: pointer;
  border-bottom: 1px solid var(--border-light);
}
.search-result-row:hover,
.search-result-row.selected { background: var(--bg-hover); }
.search-result-row.selected {
  border-left: 2px solid var(--accent);
  padding-left: 12px;
}
.search-result-repo {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  color: var(--text-muted);
}
.search-result-summary {
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.search-result-summary mark {
  background: transparent;
  color: var(--accent);
  font-weight: 700;
}
.search-no-results {
  padding: 24px 14px;
  text-align: center;
  color: var(--text-muted);
  font-size: var(--font-size-md);
}

/* Help */
.help-box {
  width: 380px;
  max-width: 90vw;
  background: var(--bg-primary);
  border: 1px solid var(--text-primary);
  align-self: flex-start;
  padding: 18px 22px;
}
.help-title {
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  margin-bottom: 14px;
}
.help-shortcuts { display: flex; flex-direction: column; gap: 6px; }
.help-row {
  display: flex; align-items: center; gap: 14px;
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  color: var(--text-secondary);
}
.help-row kbd {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 500;
  min-width: 56px;
  text-align: center;
  padding: 1px 6px;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-primary);
}
.help-dismiss {
  margin-top: 14px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  text-align: center;
}
.help-dismiss kbd {
  font-family: var(--font-mono);
  font-size: 10px;
  padding: 0 4px;
  border: 1px solid var(--border);
}

/* ============================================================
   GROUP FOCUS (j/k nav)
   ============================================================ */

.repo-group.group-focused > .repo-header {
  background: var(--accent-dim);
  border-left: 2px solid var(--accent);
}

/* ============================================================
   CONTENT
   ============================================================ */

.hidden { display: none !important; }

.loading {
  text-align: center;
  padding: 32px;
  color: var(--text-muted);
  font-size: var(--font-size-md);
}

.empty-state {
  text-align: center;
  padding: 32px 16px;
  color: var(--text-secondary);
  font-size: var(--font-size-md);
}
.empty-state-title {
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 12px;
  letter-spacing: 0.04em;
}
.empty-state-body { line-height: 1.6; }
.empty-state-body p { margin-bottom: 6px; }
.empty-state code {
  font-family: var(--font-mono);
  background: var(--bg-surface);
  padding: 1px 5px;
  font-size: 12px;
  border: 1px solid var(--border);
}

/* ============================================================
   REPO GROUP
   ============================================================ */

.repo-group {
  margin: 0;
  background: transparent;
  border: none;
  border-bottom: 1px solid var(--border);
  overflow: hidden;
}

.repo-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px;
  cursor: pointer;
  transition: background var(--transition);
  user-select: none;
}
.repo-header:hover { background: var(--bg-hover); }

.repo-header-left { display: flex; align-items: center; gap: 8px; }

.repo-chevron {
  font-size: 10px;
  color: var(--text-muted);
  transition: transform 100ms linear;
  width: 12px;
  text-align: center;
}
.repo-chevron.expanded { transform: rotate(90deg); }

.octocat-icon { opacity: 0.4; margin-right: 2px; vertical-align: -1px; flex-shrink: 0; }

.repo-header-info { display: flex; flex-direction: column; gap: 1px; }

.repo-name-display {
  font-family: var(--font-mono);
  font-weight: 700;
  font-size: var(--font-size-md);
  letter-spacing: 0;
  line-height: 1.2;
  color: var(--text-primary);
}

.repo-meta-line {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  line-height: 1.3;
}

.meta-sep {
  margin: 0 5px;
  color: var(--border);
  font-weight: 400;
}

.repo-meta-line .meta-branch { color: var(--text-secondary); }
.repo-meta-line .dirty       { color: var(--accent); font-weight: 600; }
.repo-meta-line .unpushed    { color: var(--accent); font-weight: 600; }
.repo-meta-line .clean       { color: var(--text-secondary); }
.repo-meta-line .meta-count  { color: var(--text-muted); }

.repo-header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
}

.btn-new-session {
  width: 22px;
  height: 22px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-muted);
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 500;
  line-height: 1;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: color var(--transition), border-color var(--transition), background var(--transition);
}
.btn-new-session:hover {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}

/* ============================================================
   REPO TIMELINE
   ============================================================ */

.repo-timeline {
  padding: 6px 14px 8px;
  border-top: 1px dashed var(--border);
}
.timeline-prose {
  margin: 0;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  line-height: 1.5;
  color: var(--text-secondary);
}
.timeline-link {
  color: var(--accent);
  text-decoration: none;
  cursor: pointer;
}
.timeline-link:hover { text-decoration: underline; }

/* ============================================================
   SESSION LIST + ROW
   ============================================================ */

.session-list { margin: 0; border: none; overflow: hidden; transition: max-height 200ms ease; }
.session-list.collapsed { max-height: 0 !important; }

.session-row {
  display: grid;
  grid-template-columns: 12px 1fr auto auto;
  align-items: center;
  gap: 8px;
  padding: 5px 14px;
  cursor: pointer;
  transition: background var(--transition);
  line-height: 1.4;
  border-left: 2px solid transparent;
  border-bottom: 1px solid var(--border-light);
}
.session-row:last-child,
.session-row:has(+ .show-more-btn) { border-bottom: none; }
.session-row:hover { background: var(--bg-hover); }

/* ============================================================
   STATUS DOT — replaced with glyphs via ::before
   ============================================================ */

.status-dot {
  width: 12px;
  height: 16px;
  background: transparent !important;
  border-radius: 0 !important;
  flex-shrink: 0;
  position: relative;
  animation: none !important;
  box-shadow: none !important;
}
.status-dot::before {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-mono);
  font-size: 12px;
  line-height: 1;
}
.status-dot.in-progress::before        { content: "◐"; color: var(--accent); }
.status-dot.likely-in-progress::before { content: "◑"; color: var(--text-primary); }
.status-dot.waiting-for-input::before  { content: "◌"; color: var(--accent); }
.status-dot.done::before               { content: "●"; color: var(--text-primary); }
.status-dot.likely-done::before        { content: "◯"; color: var(--text-muted); }

/* ============================================================
   SESSION SUMMARY
   ============================================================ */

.session-summary {
  font-family: var(--font-mono);
  font-size: var(--font-size-base);
  font-weight: 400;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  color: var(--text-primary);
}
.session-fresh .session-summary {
  font-weight: 500;
  color: var(--text-primary);
}

/* ============================================================
   STATUS LABEL — bracketed text instead of pill
   ============================================================ */

.status-label {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  padding: 0;
  white-space: nowrap;
  letter-spacing: 0.02em;
  background: transparent !important;
  border: none !important;
  border-radius: 0 !important;
  color: var(--text-muted);
  text-transform: lowercase;
}
.status-label::before { content: "["; }
.status-label::after  { content: "]"; }
.status-label.in-progress        { color: var(--accent); }
.status-label.likely-in-progress { color: var(--text-primary); }
.status-label.waiting-for-input  { color: var(--accent); font-weight: 600; }
.status-label.done               { color: var(--text-muted); }
.status-label.likely-done        { color: var(--text-muted); opacity: 0.7; }

/* Time / source meta */
.time-ago {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  color: var(--text-muted);
  white-space: nowrap;
  letter-spacing: 0.02em;
}

.source-badge {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  padding: 0 5px;
  white-space: nowrap;
  letter-spacing: 0.02em;
  text-transform: lowercase;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-secondary);
  line-height: 1.5;
}
.source-badge.claude { color: var(--badge-claude); }
.source-badge.codex  { color: var(--badge-codex); }

/* Active session */
.session-row.session-active {
  border-left-color: var(--accent);
  background: var(--bg-hover);
}
.session-row.session-streaming { background: var(--accent-dim); }

/* Agent picker */
.agent-picker {
  position: fixed;
  z-index: 100;
  background: var(--bg-primary);
  border: 1px solid var(--text-primary);
  min-width: 120px;
  padding: 0;
}
.agent-picker-item {
  padding: 6px 14px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  font-weight: 500;
  letter-spacing: 0.02em;
  cursor: pointer;
  color: var(--text-primary);
  border-bottom: 1px solid var(--border-light);
}
.agent-picker-item:last-child { border-bottom: none; }
.agent-picker-item:hover { background: var(--bg-hover); color: var(--accent); }

/* Show more */
.show-more-btn {
  padding: 6px 14px;
  font-family: var(--font-mono);
  font-weight: 500;
  font-size: var(--font-size-sm);
  color: var(--accent);
  cursor: pointer;
  letter-spacing: 0.02em;
  border-top: 1px dashed var(--border);
}
.show-more-btn::before { content: "› "; }
.show-more-btn:hover { background: var(--accent-dim); }

.non-repo-separator {
  padding: 16px 14px 6px;
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  font-weight: 500;
  letter-spacing: 0.04em;
  color: var(--text-muted);
  border-top: 1px solid var(--border);
  margin-top: 8px;
}
.non-repo-separator::before { content: "── "; }
.non-repo-separator::after  { content: " ──"; }

/* ============================================================
   TERMINAL PANEL
   ============================================================ */

.terminal-panel {
  position: fixed;
  bottom: 0; left: 0; right: 0;
  height: 50vh;
  background: #0a0a0a;
  border-top: 2px solid var(--accent);
  display: flex;
  flex-direction: column;
  z-index: 100;
}
.terminal-panel.hidden { display: none; }

.terminal-panel-header {
  display: flex;
  align-items: stretch;
  justify-content: space-between;
  padding: 0;
  background: #111;
  border-bottom: 1px solid #1f1f1f;
  flex-shrink: 0;
}

.terminal-tabs {
  display: flex;
  flex: 1;
  overflow-x: auto;
  scrollbar-width: none;
}
.terminal-tabs::-webkit-scrollbar { display: none; }

.terminal-tab {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: #777;
  cursor: pointer;
  white-space: nowrap;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  border-right: 1px solid #1f1f1f;
  border-bottom: 2px solid transparent;
  flex-shrink: 0;
}
.terminal-tab:hover { color: #ccc; background: #161616; }
.terminal-tab.active { color: #ccc; background: #0a0a0a; border-bottom-color: var(--accent); }
.terminal-tab.ended { color: #555; text-decoration: line-through; }

.terminal-tab-close {
  background: none; border: none; color: inherit;
  font-size: 14px; cursor: pointer; padding: 0 2px; line-height: 1; opacity: 0.5;
}
.terminal-tab-close:hover { opacity: 1; color: var(--accent); }
.terminal-tab-title { overflow: hidden; text-overflow: ellipsis; }

.terminal-panel-close {
  background: none; border: none; color: #999;
  font-size: 18px; cursor: pointer; padding: 0 12px; line-height: 1;
}
.terminal-panel-close:hover { color: var(--accent); }

#terminal-container { flex: 1; overflow: hidden; position: relative; }
.terminal-tab-container { display: none; position: absolute; inset: 4px; }
.terminal-tab-container.active { display: block; }

body.terminal-open .content { padding-bottom: calc(50vh + 24px); }

/* ============================================================
   CHAT PANEL
   ============================================================ */

.chat-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: var(--bg-primary);
  min-width: 0;
  position: relative;
}

.chat-panel-header {
  display: flex;
  align-items: stretch;
  justify-content: space-between;
  padding: 0;
  background: var(--bg-primary);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-height: 34px;
}

.chat-tabs {
  display: flex;
  flex: 1;
  overflow-x: auto;
  scrollbar-width: none;
}
.chat-tabs::-webkit-scrollbar { display: none; }

.chat-tab {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  cursor: pointer;
  max-width: 240px;
  border-right: 1px solid var(--border);
  border-bottom: 2px solid transparent;
  flex-shrink: 0;
}
.chat-tab:hover { color: var(--text-secondary); background: var(--bg-hover); }
.chat-tab.active {
  color: var(--text-primary);
  background: var(--bg-primary);
  font-weight: 600;
  border-bottom: 2px solid var(--accent);
}
.chat-tab.streaming .chat-tab-title { color: var(--accent); }

.chat-tab-title {
  overflow: hidden; text-overflow: ellipsis; white-space: nowrap; min-width: 0;
}
.chat-tab-close {
  font-size: 13px; opacity: 0.4; cursor: pointer; flex-shrink: 0; padding: 0 2px; line-height: 1;
}
.chat-tab-close:hover { opacity: 1; color: var(--accent); }

.chat-panel-controls {
  display: flex; align-items: center; gap: 8px; flex-shrink: 0; padding: 0 12px;
}

.chat-cost {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 1px 6px;
  border: 1px solid var(--border);
  white-space: nowrap;
}
.chat-cost.context-warn     { color: var(--accent); border-color: var(--accent); }
.chat-cost.context-critical { color: #fff; background: var(--accent); border-color: var(--accent); }

/* Chat body */
.chat-body { display: flex; flex: 1; overflow: hidden; min-height: 0; }

.chat-turn-sidebar {
  width: 200px;
  flex-shrink: 0;
  border-right: 1px solid var(--border);
  background: var(--bg-primary);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.chat-turn-sidebar.hidden,
.chat-turn-sidebar.collapsed { display: none; }

.turn-sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.turn-sidebar-title {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  letter-spacing: 0.04em;
}
.turn-counter {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
}

.turn-list { flex: 1; overflow-y: auto; padding: 0; }

.turn-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 8px 12px;
  cursor: pointer;
  border-left: 2px solid transparent;
  border-bottom: 1px solid var(--border-light);
}
.turn-item:hover { background: var(--bg-hover); }
.turn-item.active {
  border-left-color: var(--accent);
  background: var(--bg-hover);
}

.turn-label {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  min-width: 22px;
  flex-shrink: 0;
  font-weight: 500;
}
.turn-item.active .turn-label { color: var(--accent); }
.turn-label::before { content: "["; }
.turn-label::after  { content: "]"; }

.turn-preview {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  line-height: 1.4;
  overflow: hidden;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.turn-shortcuts {
  padding: 6px 12px;
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  border-top: 1px solid var(--border);
  text-align: center;
  flex-shrink: 0;
}

.chat-bubble.user.turn-highlight {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  transition: outline-color 1.5s ease-out;
}

.chat-messages { flex: 1; overflow-y: auto; padding: 0; position: relative; }

.chat-tab-container { display: none; padding: 16px 24px; }
.chat-tab-container.active { display: block; }

.chat-empty {
  position: absolute; inset: 0;
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  color: var(--text-muted);
}
.chat-empty.hidden { display: none; }
.chat-empty-title {
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 6px;
  letter-spacing: 0.04em;
}
.chat-empty-body {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
}

/* User messages — flat, right-aligned, with > prefix */
.chat-bubble.user {
  background: transparent;
  color: var(--accent);
  padding: 4px 0;
  border-radius: 0;
  margin: 8px 0 8px auto;
  max-width: 80%;
  width: fit-content;
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  line-height: 1.5;
  word-wrap: break-word;
  white-space: pre-wrap;
  box-shadow: none;
  text-align: right;
}
.chat-bubble.user::before {
  content: "> ";
  color: var(--accent);
  font-weight: 600;
}

/* Assistant — flat, no bubble */
.chat-bubble.assistant {
  background: transparent;
  color: var(--text-primary);
  padding: 4px 0;
  border-radius: 0;
  margin: 12px 0;
  max-width: 100%;
  width: auto;
  font-family: var(--font-body);
  font-size: var(--font-size-md);
  line-height: 1.6;
  border: none;
}

.chat-md-content h1, .chat-md-content h2, .chat-md-content h3 {
  margin: 14px 0 6px;
  font-family: var(--font-mono);
  font-weight: 700;
  letter-spacing: 0;
}
.chat-md-content h1 { font-size: 16px; }
.chat-md-content h2 { font-size: 14px; }
.chat-md-content h3 { font-size: 13px; }
.chat-md-content p  { margin: 6px 0; }

.chat-md-content pre {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  padding: 10px 12px;
  overflow-x: auto;
  font-size: var(--font-size-md);
  margin: 8px 0;
}
.chat-md-content code {
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
}
.chat-md-content :not(pre) > code {
  background: var(--bg-code-inline);
  padding: 0 4px;
}

.chat-md-content table { border-collapse: collapse; margin: 8px 0; font-size: var(--font-size-md); }
.chat-md-content th, .chat-md-content td {
  border: 1px solid var(--border-table);
  padding: 4px 10px;
  text-align: left;
}
.chat-md-content th { background: var(--bg-table-header); }

.chat-md-content ul, .chat-md-content ol { padding-left: 20px; margin: 6px 0; }

.chat-md-content blockquote {
  border-left: 2px solid var(--accent);
  margin: 8px 0;
  padding: 4px 12px;
  color: var(--text-secondary);
}
.chat-md-content a { color: var(--accent); }

/* Thinking */
.chat-thinking {
  margin: 6px 0;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  border-left: 1px solid var(--border);
  padding-left: 10px;
}
.chat-thinking summary { cursor: pointer; color: var(--text-muted); }
.chat-thinking-content {
  white-space: pre-wrap;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  margin-top: 4px;
  max-height: 200px;
  overflow-y: auto;
}

/* Tool call cards — single-line, flat */
.chat-tool-card {
  margin: 4px 0;
  border: 1px solid var(--border);
  background: transparent;
  font-size: var(--font-size-sm);
  border-left: 2px solid var(--border);
}
.chat-tool-card:has(.chat-tool-status.completed)   { border-left-color: var(--text-secondary); }
.chat-tool-card:has(.chat-tool-status.in_progress) { border-left-color: var(--accent); }
.chat-tool-card:has(.chat-tool-status.failed)      { border-left-color: var(--accent); }

.chat-tool-header {
  display: flex; align-items: center; gap: 8px;
  padding: 4px 10px;
  cursor: pointer;
  list-style: none;
}
.chat-tool-header::-webkit-details-marker { display: none; }
.chat-tool-icon { font-size: 10px; color: var(--text-muted); }
.chat-tool-icon::before { content: "▸"; }
.chat-tool-title {
  flex: 1;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-primary);
}
.chat-tool-path {
  font-family: var(--font-mono);
  color: var(--text-muted);
  font-size: var(--font-size-xs);
}
.chat-tool-status {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  padding: 0;
  background: transparent !important;
  letter-spacing: 0.02em;
}
.chat-tool-status::before { content: "["; }
.chat-tool-status::after  { content: "]"; }
.chat-tool-status.pending      { color: var(--text-muted); }
.chat-tool-status.in_progress  { color: var(--accent); }
.chat-tool-status.completed    { color: var(--text-secondary); }
.chat-tool-status.failed       { color: var(--accent); font-weight: 600; }

.chat-tool-group {
  margin: 4px 0;
  border: 1px solid var(--border);
  background: transparent;
  font-size: var(--font-size-sm);
}
.chat-tool-group > summary {
  padding: 4px 10px;
  cursor: pointer;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  list-style: none;
}
.chat-tool-group > summary::-webkit-details-marker { display: none; }

.chat-tool-body { padding: 0 10px 8px; }

.chat-tool-output {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  padding: 8px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  white-space: pre-wrap;
  word-break: break-all;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
  margin: 4px 0;
}

.chat-diff { margin: 4px 0; }
.chat-diff-header {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  color: var(--text-muted);
  padding: 2px 0;
}
.chat-diff-content {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  padding: 8px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  white-space: pre-wrap;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
}

.chat-plan {
  margin: 8px 0;
  padding: 8px 12px;
  background: transparent;
  border: 1px solid var(--border);
}
.chat-plan-title {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: 4px;
  letter-spacing: 0.04em;
}
.chat-plan-title::before { content: "── "; }
.chat-plan-title::after  { content: " ──"; }
.chat-plan ul { list-style: none; padding: 0; margin: 0; }
.chat-plan-entry {
  padding: 2px 0;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
}
.chat-plan-entry.completed { color: var(--text-secondary); }
.chat-plan-entry.failed    { color: var(--accent); }
.chat-plan-icon { margin-right: 6px; }

.chat-system-msg {
  text-align: center;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 6px;
}

.chat-local-command {
  display: flex; align-items: center; gap: 6px;
  padding: 2px 0;
  margin: 2px 0;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
}
.chat-local-cmd-icon::before { content: "$"; color: var(--accent); }
.chat-local-cmd-name { color: var(--text-secondary); }
.chat-local-cmd-output { opacity: 0.6; font-style: normal; }

.chat-terminated {
  color: var(--accent);
  border: 1px solid var(--accent);
  padding: 8px 12px;
  margin: 8px 0;
  font-family: var(--font-mono);
}

.chat-info-banner {
  background: transparent;
  border: 1px dashed var(--accent);
  padding: 8px 12px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-secondary);
  margin: 8px 0;
}

.chat-auth-banner {
  background: var(--accent-dim);
  border: 1px solid var(--accent);
  padding: 12px;
  margin: 8px 0;
  text-align: center;
}
.chat-auth-text {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--accent);
  margin-bottom: 8px;
}
.chat-auth-retry {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  padding: 4px 16px;
  background: var(--accent);
  color: #fff;
  border: none;
  cursor: pointer;
}
.chat-auth-retry:hover { opacity: 0.85; }

/* Image preview */
.chat-image-preview {
  display: none;
  flex-shrink: 0;
  gap: 8px;
  padding: 6px 14px 0;
  background: var(--bg-primary);
  border-top: 1px solid var(--border);
  overflow-x: auto;
}
.chat-image-preview.active { display: flex; }
.image-preview-thumb { position: relative; flex-shrink: 0; }
.image-preview-thumb img {
  height: 56px;
  max-width: 120px;
  object-fit: cover;
  border: 1px solid var(--border);
}
.image-preview-remove {
  position: absolute;
  top: 0; right: 0;
  width: 16px; height: 16px;
  border: 1px solid var(--text-primary);
  background: var(--bg-primary);
  color: var(--text-primary);
  font-size: 11px;
  line-height: 1;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
}
.image-preview-remove:hover { background: var(--accent); color: #fff; border-color: var(--accent); }

.chat-bubble-images {
  display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 6px;
}
.chat-bubble-img {
  max-width: 300px; max-height: 200px;
  border: 1px solid var(--border);
  object-fit: contain;
}

/* Input bar */
.chat-input-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 14px;
  background: var(--bg-primary);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}
.chat-input-prompt {
  font-family: var(--font-mono);
  font-size: 14px;
  font-weight: 600;
  color: var(--accent);
  flex-shrink: 0;
}

.chat-input {
  flex: 1;
  background: transparent;
  color: var(--text-primary);
  border: none;
  border-bottom: 1px solid var(--border);
  padding: 6px 0;
  font-family: var(--font-mono);
  font-size: var(--font-size-md);
  resize: none;
  outline: none;
  max-height: 120px;
  line-height: 1.4;
}
.chat-input:focus { border-bottom-color: var(--accent); }
.chat-input:disabled { opacity: 0.5; }

.chat-send-btn {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--accent);
  padding: 4px 10px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  font-weight: 600;
  letter-spacing: 0.04em;
  cursor: pointer;
  flex-shrink: 0;
  border-radius: 0;
  width: auto;
  height: auto;
}
.chat-send-btn:hover { background: var(--accent); color: #fff; }
.chat-send-btn:disabled { opacity: 0.3; cursor: default; }

.chat-stop-btn {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--accent);
  padding: 4px 10px;
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  font-weight: 600;
  cursor: pointer;
  flex-shrink: 0;
  border-radius: 0;
  width: auto;
  height: auto;
}
.chat-stop-btn:hover { background: var(--accent); color: #fff; }
.chat-stop-btn.hidden { display: none; }

/* ============================================================
   RESPONSIVE
   ============================================================ */

@media (max-width: 800px) {
  .header { padding-left: 14px; padding-right: 14px; }
  .header-title { font-size: 13px; }
  .app-layout { flex-direction: column; }
  .sidebar {
    width: 100% !important;
    max-width: 100vw;
    max-height: 40vh;
    border-right: none;
    border-bottom: 1px solid var(--border);
  }
  .sidebar.collapsed { max-height: 0; border-bottom: none; }
  .sidebar-resize-handle { display: none; }
  .session-row { grid-template-columns: 12px 1fr auto; gap: 8px; }
  .status-label, .time-ago { display: none; }
  .chat-bubble.assistant { max-width: 100%; }
  .chat-turn-sidebar { display: none; }
}

/* ============================================================
   DARK MODE
   ============================================================ */

html.dark {
  --bg-primary:    #0a0a0a;
  --bg-secondary:  #0a0a0a;
  --bg-hover:      #161616;
  --bg-surface:    #121212;

  --text-primary:   #e8e8e8;
  --text-secondary: #aaaaaa;
  --text-muted:     #666666;

  --border:       #1c1c1c;
  --border-light: #181818;

  --accent-dim:   rgba(255, 91, 31, 0.18);

  --bg-code:           #060606;
  --border-code:       #1c1c1c;
  --bg-code-inline:    rgba(255, 255, 255, 0.07);
  --bg-table-header:   rgba(255, 255, 255, 0.04);
  --border-table:      #2a2a2a;

  --status-done:        #888888;
  --status-likely-done: #555555;

  --badge-claude: #dddddd;
  --badge-codex:  #999999;
}

html.dark .header           { box-shadow: none; border-bottom-color: var(--border); }
html.dark .repo-group       { box-shadow: none; }
html.dark .search-overlay   { background: rgba(0, 0, 0, 0.65); }
html.dark .help-overlay     { background: rgba(0, 0, 0, 0.65); }
html.dark .source-badge     { border-color: var(--border); }
html.dark .sidebar          { border-right-color: var(--border); }
html.dark .time-seg.active  { background: var(--text-primary); color: var(--bg-primary); }
html.dark .meta-sep         { color: var(--border); }
html.dark .repo-meta-line .dirty { color: var(--accent); }
html.dark .repo-meta-line .clean { color: var(--text-secondary); }
html.dark .agent-picker     { background: var(--bg-primary); border-color: var(--text-primary); }
html.dark .agent-picker-item:hover { background: var(--bg-hover); }
html.dark .chat-bubble.assistant { border: none; }

